const dia = "segunda";

switch (dia) {
  case "segunda":
    console.log("Início da semana.");
    break;
  case "sexta":
    console.log("Fim da semana útil.");
    break;
  default:
    console.log("Outro dia.");
}

const statusPedido = "em-analise";

switch (statusPedido) {
  case "aprovado":
    console.log("Pedido aprovado.");
    break;
  case "rejeitado":
    console.log("Pedido rejeitado.");
    break;
  default:
    console.log("Status ainda não classificado.");
}

const nivel = 1;

switch (nivel) {
  case 1:
    console.log("Nível 1");
  case 2:
    console.log("Nível 2");
  default:
    console.log("Fim");
}

const dia = "sabado";

switch (dia) {
  case "sabado":
  case "domingo":
    console.log("Fim de semana");
    break;
  default:
    console.log("Dia útil");
}
